# fix_dashboard_dark.ps1 - Dashboard con dark mode
Write-Host "Aplicando dark mode al Dashboard..." -ForegroundColor Cyan
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\dashboard\pages\DashboardPage.tsx", $text, [System.Text.Encoding]::UTF8)
Write-Host "Listo!" -ForegroundColor Green
